import axios from "axios";

const friendAdd = async ({friend_id}) => {
    try{
        const request = await axios.post('/add/friend', {friend_id}, {withCredentials: true});
        return request.data;
    }catch(err){
        return{success: false, message: "서버 오류"}
    }
}
export default friendAdd;
